<template>
  <view class="page notification-settings-page">
    <!-- Header banner -->
    <view class="section settings-header-card">
      <view class="settings-header-wrap">
        <view class="settings-header-meta">
          <view class="settings-header-title">通知服务管理</view>
          <view class="settings-header-desc"
            >您可以自主开启或关闭特定业务节点的短信/小程序推送。</view
          >
        </view>
      </view>
    </view>

    <!-- Notification Scene Cards -->
    <view v-for="group in groups" :key="group.sceneCode" class="section scene-setting-card">
      <view class="scene-header">
        <view class="scene-dot"></view>
        <text class="scene-name">{{
          notificationSceneText[group.sceneCode] || group.sceneCode
        }}</text>
      </view>

      <view class="channels-list">
        <view
          v-for="item in group.items"
          :key="item.notificationChannel"
          class="row-between channel-setting-row"
        >
          <view class="channel-info">
            <text class="channel-label"
              >{{
                notificationChannelText[item.notificationChannel] || item.notificationChannel
              }}通知</text
            >
          </view>
          <switch
            color="#F97316"
            :checked="item.isEnabled"
            @change="toggle(item, $event.detail.value)"
            style="transform: scale(0.85)"
          />
        </view>
      </view>
    </view>
  </view>
</template>

<script>
import { api, requireLogin } from '../../utils/api.js';
import { notificationChannelText, notificationSceneText } from '../../utils/format.js';

export default {
  data() {
    return {
      groups: [],
      notificationSceneText,
      notificationChannelText,
    };
  },
  onLoad() {
    if (requireLogin()) this.load();
  },
  methods: {
    async load() {
      const data = await api.notificationSettings();
      const map = {};
      for (const item of data.items || []) {
        if (!map[item.sceneCode]) map[item.sceneCode] = { sceneCode: item.sceneCode, items: [] };
        map[item.sceneCode].items.push(item);
      }
      this.groups = Object.values(map);
    },
    async toggle(item, isEnabled) {
      item.isEnabled = isEnabled;
      await api.updateNotificationSetting({
        sceneCode: item.sceneCode,
        notificationChannel: item.notificationChannel,
        isEnabled,
      });
    },
  },
};
</script>

